parameters.jsonBody:
{
  "model": "qwen-plus",
  "messages": [
    {
      "role": "system",
      "content": "Você é um especialista em arquitetura de software e desenvolvimento. Sua tarefa é analisar as necessidades do projeto e recomendar o melhor stack tecnológico. Forneça uma resposta estruturada em JSON com os seguintes campos: frontend, backend, database, cloud_provider, devops_tools, justification. Seja específico e justifique cada escolha baseada nas necessidades informadas."
    },
    {
      "role": "user",
      "content": "{{ $json.body.project_requirements }}"
    }
  ],
  "temperature": 0.7,
  "max_tokens": 2000
}

parameters.jsCode:
const response = $input.first().json;

// Extrair o conteúdo da resposta do Qwen
let content = '';
if (response.choices && response.choices.length > 0) {
  content = response.choices[0].message.content;
}

// Tentar parsear o JSON da resposta
let techStack = {};
try {
  // Remover possíveis marcações de código markdown
  const cleanContent = content.replace(/```json\n?/g, '').replace(/```\n?/g, '').trim();
  techStack = JSON.parse(cleanContent);
} catch (error) {
  // Se não conseguir parsear, retorna o conteúdo bruto
  techStack = {
    raw_response: content,
    parsing_error: error.message
  };
}

return {
  json: {
    success: true,
    project_requirements: $input.first().json.body?.project_requirements || 'Não informado',
    recommended_stack: techStack,
    model_used: 'qwen-plus',
    timestamp: new Date().toISOString()
  }
};
